mapper.update:
	UPDATE EVA_POOL_APPL
	    SET SIGN_1	 		= #{sign1, jdbcType=CLOB}	
	    ,SEC_PLEDGE_YN      = 'Y'    
	    ,SEC_PLEDGE_YN_DT   = SYSDATE	
	WHERE 
 		 DI = #{di}
 		 AND USR_ID = #{usrId}   		
 		 AND PERIOD_DIV_CD = #{periodDivCd}
	     AND EVA_YEAR = #{evaYear}
	     AND POOL_CD = #{poolCd}
